from __future__ import annotations

import shlex
import subprocess
from pathlib import Path
import re

from .base import BuilderBase
from .registry import BuilderRegistry


_SLUG_RE = re.compile(r"^[a-z0-9][a-z0-9-]*$")
_ID_RE = re.compile(r"^[A-Za-z0-9][A-Za-z0-9_-]*$")


class VerifyScriptBuilder(BuilderBase):
    BUILDER_TYPE = "verify-script"

    INPUT_SCHEMA = {
        "type": "object",
        "required": ["id", "slug", "checks"],
    }

    def validate_input(self, params: dict) -> dict:
        if not isinstance(params, dict):
            raise ValueError("input must be an object")

        script_id = str(params.get("id", "")).strip()
        slug = str(params.get("slug", "")).strip()
        checks = params.get("checks")
        setup = str(params.get("setup", "")).strip()
        teardown = str(params.get("teardown", "")).strip()

        if not script_id or not _ID_RE.match(script_id):
            raise ValueError("id must match ^[A-Za-z0-9][A-Za-z0-9_-]*$")
        if not slug or not _SLUG_RE.match(slug):
            raise ValueError("slug must match ^[a-z0-9][a-z0-9-]*$")
        if not isinstance(checks, list) or not checks:
            raise ValueError("checks must be a non-empty array")

        normalized_checks: list[dict] = []
        for index, check in enumerate(checks, start=1):
            if not isinstance(check, dict):
                raise ValueError(f"checks[{index}] must be an object")
            desc = str(check.get("desc", "")).strip()
            cmd = str(check.get("cmd", "")).strip()
            if not desc:
                raise ValueError(f"checks[{index}].desc is required")
            if not cmd:
                raise ValueError(f"checks[{index}].cmd is required")
            normalized_checks.append({"desc": desc, "cmd": cmd})

        return {
            "id": script_id,
            "slug": slug,
            "checks": normalized_checks,
            "setup": setup,
            "teardown": teardown,
        }

    def generate(self, params: dict, seed: dict | None) -> list[dict]:
        del seed

        verify_dir = Path(self.project_root) / "verify"
        verify_dir.mkdir(parents=True, exist_ok=True)

        script_path = verify_dir / f"{params['id']}-{params['slug']}.sh"

        lines = [
            "#!/bin/bash",
            "set -euo pipefail",
            f"# Generated by {self.BUILDER_TYPE}",
            "",
            "PASS=0",
            "FAIL=0",
            "D=$(mktemp -d /tmp/helix-verify-XXXXXX)",
            "",
            f"SETUP_CMD={shlex.quote(params['setup'])}",
            f"TEARDOWN_CMD={shlex.quote(params['teardown'])}",
            "",
            "run_check() {",
            "  local desc=\"$1\"",
            "  local cmd=\"$2\"",
            "  set +e",
            "  eval \"$cmd\" >/dev/null 2>&1",
            "  local rc=$?",
            "  set -e",
            "  if [[ $rc -eq 0 ]]; then",
            "    PASS=$((PASS + 1))",
            "    echo \"PASS: $desc\"",
            "  else",
            "    FAIL=$((FAIL + 1))",
            "    echo \"FAIL: $desc\"",
            "  fi",
            "}",
            "",
            "cleanup() {",
            "  if [[ -n \"$TEARDOWN_CMD\" ]]; then",
            "    set +e",
            "    eval \"$TEARDOWN_CMD\" >/dev/null 2>&1",
            "    set -e",
            "  fi",
            "  rm -rf \"$D\"",
            "}",
            "",
            "trap cleanup EXIT",
            "cd \"$D\"",
            "",
            "if [[ -n \"$SETUP_CMD\" ]]; then",
            "  echo \"== setup ==\"",
            "  eval \"$SETUP_CMD\" >/dev/null 2>&1",
            "fi",
            "",
        ]

        for check in params["checks"]:
            lines.append(f"run_check {shlex.quote(check['desc'])} {shlex.quote(check['cmd'])}")

        lines.extend(
            [
                "",
                'echo "Results: ${PASS} passed, ${FAIL} failed"',
                "if [[ $FAIL -eq 0 ]]; then",
                "  exit 0",
                "fi",
                "exit 1",
                "",
            ]
        )

        script_path.write_text("\n".join(lines), encoding="utf-8")
        script_path.chmod(0o755)

        return [
            {
                "path": str(script_path.relative_to(self.project_root)),
                "kind": "verify-script",
            }
        ]

    def validate_output(self, artifacts: list[dict]) -> dict:
        if not isinstance(artifacts, list) or not artifacts:
            raise ValueError("artifacts are required")

        script_paths = [_artifact_path(self.project_root, artifact) for artifact in artifacts]
        if len(script_paths) != 1:
            raise ValueError("verify-script expects one artifact")

        script_path = script_paths[0]
        if not script_path.exists():
            raise ValueError(f"script not found: {script_path}")

        completed = subprocess.run(
            ["bash", "-n", str(script_path)],
            capture_output=True,
            text=True,
            check=False,
        )
        if completed.returncode != 0:
            stderr = (completed.stderr or completed.stdout).strip()
            raise ValueError(f"bash syntax check failed: {stderr}")

        return {
            "valid": True,
            "checked_files": [str(script_path)],
            "quality_score": 100,
        }


def _artifact_path(project_root: str, artifact: dict) -> Path:
    path_value = artifact.get("path") if isinstance(artifact, dict) else None
    if not isinstance(path_value, str) or not path_value:
        raise ValueError("artifact.path is required")

    path = Path(path_value)
    if not path.is_absolute():
        path = Path(project_root) / path
    return path


BuilderRegistry.register(VerifyScriptBuilder)
